"use client";

import * as React from "react";
import {
  IconAnchor,
  IconArrowRight,
  IconDownload,
  IconFileText,
  IconRefresh,
  IconShip,
} from "@tabler/icons-react";
import {
  ActionQueue,
  Alert,
  AlertDescription,
  AlertTitle,
  ApprovalSteps,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Header,
  HeaderActions,
  HeaderBrand,
  ListCard,
  MetadataList,
  PageHeader,
  SectionList,
  Separator,
  StatGroup,
  type ActionItem,
  type ApprovalStep,
  type ListCardSeverity,
  type MetadataListItem,
  type SectionListSection,
} from "@gunjo/ui";

import {
  docGroups,
  exportCustoms,
  importCustoms,
  notices,
  shipment,
  stages,
  vesselSpec,
  type CustomsStep,
  type DocStatus,
  type ShipmentStage,
} from "./data";

/* ------------------------------------------------------------------ */
/* Mapping helpers (pure — could live server-side, kept here for the   */
/* single-file screen; no React/hook usage)                            */
/* ------------------------------------------------------------------ */

const DOC_STATUS: Record<DocStatus, { label: string; variant: "success" | "warning" | "info"; sev: ListCardSeverity }> = {
  available: { label: "閲覧可", variant: "success", sev: "success" },
  pending: { label: "発行待ち", variant: "info", sev: "neutral" },
  review: { label: "確認中", variant: "warning", sev: "warning" },
};

/** ShipmentStage → ApprovalStep. 日付は `timestamp` に丸ごと入れる（複数週対応）。 */
function stageToApprovalStep(s: ShipmentStage): ApprovalStep {
  return {
    label: s.label,
    state: s.state,
    actor: s.carrier ? `${s.location} ・ ${s.carrier}` : s.location,
    // ここが肝: free-form ReactNode なので "2025/05/16 〜 05/29" のような
    // 複数週の日付レンジでもそのまま渡せる（HH:MM 制約が無い）。
    timestamp: s.date,
    comment: s.note,
  };
}

function customsToApprovalStep(c: CustomsStep): ApprovalStep {
  return {
    label: c.label,
    state: c.state,
    actor: c.actor,
    timestamp: c.timestamp,
    comment: c.comment,
  };
}

/* ------------------------------------------------------------------ */
/* Screen                                                              */
/* ------------------------------------------------------------------ */

export default function IntlShipmentPage() {
  const stageSteps = React.useMemo(() => stages.map(stageToApprovalStep), []);
  const exportSteps = React.useMemo(() => exportCustoms.map(customsToApprovalStep), []);
  const importSteps = React.useMemo(() => importCustoms.map(customsToApprovalStep), []);

  const vesselItems: MetadataListItem[] = React.useMemo(
    () => vesselSpec.map((v) => ({ label: v.label, value: v.value, description: v.description })),
    []
  );

  const noticeItems: ActionItem[] = React.useMemo(
    () =>
      notices.map((n) => ({
        id: n.id,
        severity: n.severity,
        kind: n.kind,
        title: n.title,
        detail: n.detail,
        meta: n.meta,
        actions:
          n.severity === "critical" || n.severity === "warning" ? (
            <Button size="sm" variant={n.severity === "critical" ? "destructive" : "outline"}>
              対応する
            </Button>
          ) : undefined,
      })),
    []
  );

  const docSections: SectionListSection[] = React.useMemo(
    () =>
      docGroups.map((g) => {
        const ready = g.docs.filter((d) => d.status === "available").length;
        return {
          key: g.key,
          title: g.title,
          sublabel: g.sublabel,
          meta: `${ready} / ${g.docs.length} 件 閲覧可`,
          content: (
            <div className="flex flex-col gap-2 p-3">
              {g.docs.map((d) => {
                const ds = DOC_STATUS[d.status];
                return (
                  <ListCard
                    key={d.id}
                    severity={ds.sev}
                    leading={<IconFileText className="size-5 text-muted-foreground" aria-hidden="true" />}
                    title={d.title}
                    description={d.meta}
                    status={<Badge variant={ds.variant}>{ds.label}</Badge>}
                    meta={d.format}
                    trailing={
                      d.status === "available" ? (
                        <Button size="sm" variant="ghost" aria-label={`${d.title} をダウンロード`}>
                          <IconDownload className="size-4" aria-hidden="true" />
                          表示
                        </Button>
                      ) : null
                    }
                  />
                );
              })}
            </div>
          ),
        };
      }),
    []
  );

  const heroStats = React.useMemo(
    () => [
      { label: "現在のステージ", value: shipment.currentStage, hint: "輸入通関 審査中" },
      { label: "ETA（揚港入港）", value: shipment.eta, hint: "実績・遅延なし" },
      { label: "輸送モード", value: shipment.mode, hint: shipment.incoterms },
      { label: "コンテナ", value: "TCLU 783914-2", hint: "40HC × 1本" },
    ],
    []
  );

  return (
    <div className="min-h-screen bg-muted/20">
      {/* ── デスクトップ chrome（Header）────────────────────────── */}
      <Header className="sticky top-0 z-40">
        <HeaderBrand>
          <IconShip className="size-6 text-primary" aria-hidden="true" />
          <span className="text-base font-semibold">蒼海ロジスティクス｜貨物追跡ポータル</span>
        </HeaderBrand>
        <HeaderActions>
          <Badge variant="outline">荷主: 群青物産</Badge>
          <Button variant="outline" size="sm">
            <IconRefresh className="size-4" aria-hidden="true" />
            最新の状況に更新
          </Button>
        </HeaderActions>
      </Header>

      {/* ── ページバー ──────────────────────────────────────────── */}
      <PageHeader
        title={`B/L ${shipment.blNo}`}
        subtitle={`${shipment.origin.port}（${shipment.origin.code}）→ ${shipment.destination.port}（${shipment.destination.code}）`}
        sticky={false}
        actions={
          <Button variant="ghost" size="sm">
            <IconDownload className="size-4" aria-hidden="true" />
            一括ダウンロード
          </Button>
        }
      />

      <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6 lg:px-8">
        {/* ── 貨物サマリ（ヒーロー）────────────────────────────── */}
        <Card className="mb-6">
          <CardContent className="p-6">
            <div className="flex flex-wrap items-start justify-between gap-4">
              <div className="min-w-0">
                <div className="flex flex-wrap items-center gap-2">
                  <h2 className="text-2xl font-bold tracking-tight">{shipment.blNo}</h2>
                  <Badge variant="info" icon={<IconShip aria-hidden="true" />}>
                    {shipment.mode}
                  </Badge>
                  <Badge variant="warning">{shipment.currentStage}</Badge>
                </div>
                {/* 仕出地 → 仕向地 のルート見出し */}
                <div className="mt-3 flex flex-wrap items-center gap-x-3 gap-y-1 text-sm">
                  <span className="inline-flex items-center gap-1.5 font-medium">
                    <IconAnchor className="size-4 text-muted-foreground" aria-hidden="true" />
                    {shipment.origin.port}
                    <span className="text-xs text-muted-foreground">{shipment.origin.code}</span>
                  </span>
                  <IconArrowRight className="size-4 text-muted-foreground" aria-hidden="true" />
                  <span className="inline-flex items-center gap-1.5 font-medium">
                    <IconAnchor className="size-4 text-muted-foreground" aria-hidden="true" />
                    {shipment.destination.port}
                    <span className="text-xs text-muted-foreground">{shipment.destination.code}</span>
                  </span>
                  <Separator orientation="vertical" className="hidden h-4 sm:block" />
                  <span className="text-muted-foreground">
                    ETD {shipment.etd} ／ ETA {shipment.eta}
                  </span>
                </div>
              </div>
            </div>

            <Separator className="my-5" />

            <MetadataList
              layout="horizontal"
              items={[
                { label: "ブッキング番号", value: shipment.bookingNo },
                { label: "シッパー（仕入先）", value: shipment.shipper },
                { label: "コンサイニー（荷受人）", value: shipment.consignee },
                { label: "フォワーダー / 海貨", value: shipment.forwarder },
                { label: "通関業者", value: shipment.broker },
                { label: "個数 / 容積 / 重量", value: `${shipment.pieces}`, description: `${shipment.measurement} ・ ${shipment.grossWeight}` },
              ]}
            />
          </CardContent>
        </Card>

        {/* ── KPI ストリップ ───────────────────────────────────── */}
        <StatGroup className="mb-6" cols={{ base: 2, md: 4 }} items={heroStats} />

        {/* ── 要対応・お知らせ ─────────────────────────────────── */}
        <section aria-labelledby="notices-h" className="mb-6">
          <h2 id="notices-h" className="mb-3 text-lg font-semibold">
            要対応・お知らせ
          </h2>
          <ActionQueue items={noticeItems} aria-label="要対応・お知らせ一覧" />
        </section>

        {/* ── 2カラム: 左=追跡タイムライン / 右=スペック+通関 ──── */}
        <div className="grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,1.4fr)_minmax(0,1fr)]">
          {/* 左: 輸送ステージ追跡（複数週・日付つき）──────────── */}
          <Card>
            <CardHeader>
              <CardTitle as="h2" className="text-lg">
                輸送ステージの追跡
              </CardTitle>
              <p className="text-sm text-muted-foreground">
                輸出通関 → 船積 → 海上輸送 → 着港 → 輸入通関 → 国内配送 → 納品（5/12〜6/5）
              </p>
            </CardHeader>
            <CardContent>
              {/*
                ApprovalSteps を「日付つき・複数週」の輸送タイムラインに転用。
                timestamp が free-form ReactNode なので "2025/05/16 〜 05/29" の
                ようなレンジも入る。actor に 場所・本船名 を寄せている。
              */}
              <ApprovalSteps
                steps={stageSteps}
                stateLabels={{
                  approved: "完了",
                  current: "進行中",
                  pending: "未着手",
                }}
              />
            </CardContent>
          </Card>

          {/* 右: 本船情報 + 通関 ─────────────────────────────── */}
          <div className="flex flex-col gap-6">
            <Card>
              <CardHeader>
                <CardTitle as="h2" className="text-lg">
                  本船 / フライト情報
                </CardTitle>
              </CardHeader>
              <CardContent>
                <MetadataList items={vesselItems} />
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle as="h2" className="text-lg">
                  通関の状況
                </CardTitle>
                <p className="text-sm text-muted-foreground">申告 → 審査 → 許可 / 納税</p>
              </CardHeader>
              <CardContent className="flex flex-col gap-5">
                <Alert variant="warning">
                  <AlertTitle as="h3">輸入通関は審査中です</AlertTitle>
                  <AlertDescription>
                    原産地証明（Form A）の照会対応中。関税・消費税の納付後に輸入許可となります（見込 6/2）。
                  </AlertDescription>
                </Alert>

                <div>
                  <h3 className="mb-2 text-sm font-semibold text-muted-foreground">輸出通関（中国側）</h3>
                  <ApprovalSteps variant="compact" steps={exportSteps} />
                </div>

                <Separator />

                <div>
                  <h3 className="mb-2 text-sm font-semibold text-muted-foreground">輸入通関（日本側）</h3>
                  <ApprovalSteps
                    variant="compact"
                    steps={importSteps}
                    stateLabels={{ current: "審査中", approved: "完了", pending: "未着手" }}
                  />
                </div>
              </CardContent>
            </Card>
          </div>
        </div>

        {/* ── 書類 ─────────────────────────────────────────────── */}
        <section aria-labelledby="docs-h" className="mt-6">
          <div className="mb-3 flex items-center justify-between">
            <h2 id="docs-h" className="text-lg font-semibold">
              書類
            </h2>
            <Button variant="outline" size="sm">
              <IconDownload className="size-4" aria-hidden="true" />
              全書類をZIPで取得
            </Button>
          </div>
          <Card>
            <CardContent className="p-0">
              <SectionList sections={docSections} label="貨物に紐づく書類一覧" />
            </CardContent>
          </Card>
        </section>

        <footer className="mt-8 border-t border-border pt-4 text-xs text-muted-foreground">
          蒼海ロジスティクス株式会社 貨物追跡ポータル ・ お問い合わせ: 通関部 03-XXXX-XXXX ・
          表示内容は NACCS / 船社トラッキングと連携し随時更新されます。
        </footer>
      </main>
    </div>
  );
}

/**
 * 国際輸送・通関追跡ポータル — ダミーデータ（荷主向け）。
 *
 * このファイルは純粋なデータ／型のみ。関数 prop を持たないため Server Component
 * からも安全に import できる（"use client" を付けない）。
 *
 * シナリオ: 上海(SHA/上海港) → 東京(TYO/東京港) の海上 FCL 輸入。
 * 輸出通関 5/12 → 船積 5/15 → 海上輸送 5/16〜5/29 → 着港 5/30
 *   → 輸入通関許可 6/2 → 国内配送 6/4 → 納品 6/5。
 * 「現在」は 6/1（輸入通関 審査中・本船は揚地に着いた直後）の想定。
 */

import type { ApprovalStepState } from "@gunjo/ui";

/* ------------------------------------------------------------------ */
/* 貨物サマリ                                                          */
/* ------------------------------------------------------------------ */

export interface ShipmentSummary {
  blNo: string;
  bookingNo: string;
  containerNo: string;
  mode: "海上 / FCL" | "海上 / LCL" | "航空";
  shipper: string;
  consignee: string;
  forwarder: string;
  broker: string;
  origin: { port: string; code: string; country: string };
  destination: { port: string; code: string; country: string };
  currentStage: string;
  etd: string;
  eta: string;
  pieces: string;
  grossWeight: string;
  measurement: string;
  incoterms: string;
}

export const shipment: ShipmentSummary = {
