  forwarder: "蒼海ロジスティクス株式会社（NVOCC）",
  broker: "蒼海ロジスティクス 通関部（東京税関 芝浦出張所）",
  origin: { port: "上海港", code: "CNSHA", country: "中国" },
  destination: { port: "東京港", code: "JPTYO", country: "日本" },
  currentStage: "輸入通関（審査中）",
  etd: "2025/05/15",
  eta: "2025/05/30",
  pieces: "パレット 18 / カートン 540",
  grossWeight: "12,480 kg",
  measurement: "48.6 CBM",
  incoterms: "FOB Shanghai",
};

/* ------------------------------------------------------------------ */
/* 輸送ステージ（複数週にまたがる日付つきタイムライン）                */
/* ------------------------------------------------------------------ */

/** ステージの進行状態。ApprovalSteps の state にそのまま渡す。 */
export type StageState = ApprovalStepState; // pending | current | approved | rejected | skipped

export interface ShipmentStage {
  /** ステージ名（輸出通関 / 船積 …）。 */
  label: string;
  state: StageState;
  /** 場所（積港 / 揚港 / CY / 営業所）。 */
  location: string;
  /** 担当キャリア・本船名・便名など。 */
  carrier?: string;
  /**
   * 日付（＋必要なら時刻）。**複数週にまたがる** ので "MM/DD" ではなく
   * "YYYY/MM/DD HH:mm" 等の完全な日付文字列を入れる。これがこの画面の肝。
   */
  date: string;
  /** 補足（実績 vs 予定、メモ）。 */
  note?: string;
}

