/* ------------------------------------------------------------------ */
/* 通関ステータス（申告 → 審査 → 許可 / 納税）                          */
/* ------------------------------------------------------------------ */

export interface CustomsStep {
  label: string;
  state: StageState;
  actor?: string;
  timestamp?: string;
  comment?: string;
}

/** 輸出通関（中国側）— 完了済み。 */
export const exportCustoms: CustomsStep[] = [
  { label: "輸出申告", state: "approved", actor: "SH-Customs", timestamp: "2025/05/12 10:05" },
  { label: "審査・検査", state: "approved", actor: "上海税関", timestamp: "2025/05/12 13:10", comment: "書類審査のみ（区分1相当）。検査なし。" },
