  { label: "関税・消費税の納付", state: "pending", actor: "群青物産（蒼海が代行）", timestamp: "予定 6/2", comment: "概算 関税 ¥184,200 / 消費税 ¥612,400。リアルタイム口座振替予定。" },
  { label: "輸入許可（引取）", state: "pending", actor: "東京税関", timestamp: "予定 6/2" },
];

/* ------------------------------------------------------------------ */
/* 本船 / フライト情報（スペックブロック）                              */
/* ------------------------------------------------------------------ */

export interface VesselSpec {
  label: string;
  value: string;
  description?: string;
}

export const vesselSpec: VesselSpec[] = [
  { label: "本船名 / 航海番号", value: "EVER GLOBE / V.0148-E", description: "母船・直航（フィーダー無し）" },
  { label: "船社（キャリア）", value: "Evergreen Line", description: "SCAC: EGLV" },
  { label: "積港（POL）", value: "上海港 揚山 / CNSHA" },
  { label: "揚港（POD）", value: "東京港 大井 / JPTYO" },
  { label: "ETD（出港）", value: "2025/05/15 09:40", description: "実績" },
  { label: "ETA（入港）", value: "2025/05/30 06:10", description: "実績（当初予定どおり）" },
  { label: "本船入港バース", value: "大井 6/7号 ターミナル" },
  { label: "コンテナ番号 / タイプ", value: "TCLU 783914-2", description: "40ft High Cube ドライ × 1本" },
];

/* ------------------------------------------------------------------ */
/* 書類（グループ化したリスト）                                         */
/* ------------------------------------------------------------------ */

export type DocStatus = "available" | "pending" | "review";

export interface ShipmentDoc {
  id: string;
  title: string;
  meta: string;
  format: string;
  status: DocStatus;
}

export interface DocGroup {
  key: string;
  title: string;
  sublabel: string;
  docs: ShipmentDoc[];
}

export const docGroups: DocGroup[] = [
  {
    key: "transport",
    title: "船積書類",
    sublabel: "B/L・船積関連",
    docs: [
